        @{ name = "P22"; color = "RED";    description = "Launch -- Oracle production deploy + Vercel + monitoring + soft-launch" }
    )
    Status = @(
        @{ name = "Backlog";     color = "GRAY";   description = "Not yet triaged or scheduled" }
        @{ name = "Todo";        color = "BLUE";   description = "Triaged and ready to be picked up this phase" }
        @{ name = "Ready";       color = "GREEN";  description = "All prerequisites met, ready to start" }
        @{ name = "In progress"; color = "YELLOW"; description = "Actively being worked on" }
        @{ name = "In review";   color = "ORANGE"; description = "PR open, awaiting CI + review" }
