        @{ name = "Done";        color = "PURPLE"; description = "Shipped and verified" }
    )
}

# ---------------------------------------------------------------------------
# GraphQL mutation to update single-select field options
# ---------------------------------------------------------------------------

$mutation = @'
mutation($fid: ID!, $opts: [ProjectV2SingleSelectFieldOptionInput!]) {
  updateProjectV2Field(input: { fieldId: $fid, singleSelectOptions: $opts }) {
    projectV2Field {
      ... on ProjectV2SingleSelectField {
        id
        name
        options { id name description }
      }
    }
  }
}
'@

Write-Host "==> Updating single-select fields with rich descriptions + colours"
foreach ($fieldName in $FieldOptionSpec.Keys) {
    $fieldId = $FieldIds[$fieldName]
    if (-not $fieldId) {
        Write-Host "  ! Field ID not configured for: $fieldName (skipping)"
        continue
    }
    $opts = $FieldOptionSpec[$fieldName]
    $payload = @{ query = $mutation; variables = @{ fid = $fieldId; opts = $opts } } | ConvertTo-Json -Depth 8
    $tmp = [System.IO.Path]::GetTempFileName()
    [System.IO.File]::WriteAllText($tmp, $payload, [System.Text.UTF8Encoding]::new($false))
    $result = gh api graphql --input "$tmp" 2>&1
    Remove-Item $tmp
    $parsed = $result | ConvertFrom-Json
    if ($parsed.errors) {
        Write-Host "  ! FAILED: $fieldName -- $($parsed.errors | ConvertTo-Json -Compress)"
        continue
    }
    $newOpts = $parsed.data.updateProjectV2Field.projectV2Field.options
    Write-Host "  ~ updated: $fieldName ($($newOpts.Count) options w/ descriptions + colours)"
}

